double calculate_probability(int n, int *p, int *a, int *b) {
    double probability = 0.0;
    int *numbers = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        numbers[i] = a[i];
    }
    do {
        int valid = 1;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (numbers[i] == numbers[j]) {
                    valid = 0;
                    break;
                }
            }
            if (!valid) break;
        }
        if (valid) {
            double prob = 1.0;
            for (int i = 0; i < n; i++) {
                if (numbers[i] == a[i]) {
                    prob *= (double)p[i] / 100.0;
                } else {
                    prob *= (double)(100 - p[i]) / 100.0;
                }
            }
            probability += prob;
        }
    } while (next_permutation(numbers, n));
    free(numbers);
    return probability;
}

int next_permutation(int *array, int n) {
    int i = n - 2;
    while (i >= 0 && array[i] >= array[i + 1]) i--;
    if (i < 0) return 0;
    int j = n - 1;
    while (array[j] <= array[i]) j--;
    int temp = array[i];
    array[i] = array[j];
    array[j] = temp;
    int left = i + 1;
    int right = n - 1;
    while (left < right) {
        temp = array[left];
        array[left] = array[right];
        array[right] = temp;
        left++;
        right--;
    }
    return 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int *p = (int*)malloc(n * sizeof(int));
        int *a = (int*)malloc(n * sizeof(int));
        int *b = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d", &p[i], &a[i], &b[i]);
        }
        double probability = calculate_probability(n, p, a, b);
        printf("%.6f\n", probability);
        free(p);
        free(a);
        free(b);
    }
    return 0;
}

