        }
    }

    public static double calculateProbability(int n, int[] p, int[] a, int[] b) {
        double probability = 0.0;
        int[] numbers = Arrays.copyOf(a, n);
        do {
            int valid = 1;
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    if (numbers[i] == numbers[j]) {
                        valid = 0;
                        break;
                    }
                }
                if (valid == 0) break;
            }
            if (valid == 1) {
                double prob = 1.0;
                for (int i = 0; i < n; i++) {
                    if (numbers[i] == a[i]) {
                        prob *= (double)p[i] / 100.0;
                    } else {
                        prob *= (double)(100 - p[i]) / 100.0;
                    }
                }
                probability += prob;
            }
        } while (nextPermutation(numbers));
        return probability;
    }

    public static boolean nextPermutation(int[] array) {
        int i = array.length - 2;
        while (i >= 0 && array[i] >= array[i + 1]) i--;
        if (i < 0) return false;
        int j = array.length - 1;
        while (array[j] <= array[i]) j--;
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp;
        int left = i + 1;
        int right = array.length - 1;
        while (left < right) {
            temp = array[left];
            array[left] = array[right];
            array[right] = temp;
            left++;
            right--;
        }
        return true;
    }
