function calculateProbability(n, p, a, b) {
    let probability = 0.0;
    let numbers = a.slice();
    let permutations = getPermutations(numbers);
    for (let permutation of permutations) {
        let valid = 1;
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                if (permutation[i] == permutation[j]) {
                    valid = 0;
                    break;
                }
            }
            if (valid == 0) break;
        }
        if (valid == 1) {
            let prob = 1.0;
            for (let i = 0; i < n; i++) {
                if (permutation[i] == a[i]) {
                    prob *= p[i] / 100.0;
                } else {
                    prob *= (100 - p[i]) / 100.0;
                }
            }
            probability += prob;
        }
    }
    return probability;
}

function getPermutations(array) {
    if (array.length == 1) return [array];
    let permutations = [];
    for (let i = 0; i < array.length; i++) {
        let rest = array.slice(0, i).concat(array.slice(i + 1));
        for (let p of getPermutations(rest)) {
            permutations.push([array[i]].concat(p));
        }
    }
    return permutations;
}

